// ❌ BAD - putting infrastructure audit fields directly on the domain class
public class Invoice
{
    public int Id { get; set; }
    public decimal Amount { get; set; }
    public DateTime CreatedAt { get; set; }  // pollutes the domain model
    public DateTime LastModified { get; set; } // pollutes the domain model
}

// ✅ GOOD - keep the domain clean, use shadow properties for audit columns
public class Invoice
{
    public int Id { get; set; }
    public decimal Amount { get; set; }
    // no audit fields on the class
}
