// ❌ BAD - checking IsDeleted manually in every single query; developers forget it
var products = await ctx.Products
    .Where(p => !p.IsDeleted && p.CategoryId == categoryId)
    .ToListAsync();

// ✅ GOOD - register a global filter once, applied automatically everywhere
// In IEntityTypeConfiguration<Product>:
builder.HasQueryFilter(p => !p.IsDeleted);

// In DbContext SaveChanges override - convert deletes to soft deletes:
foreach (var entry in ChangeTracker.Entries<ISoftDelete>()
    .Where(e => e.State == EntityState.Deleted))
{
    entry.State = EntityState.Modified;
    entry.Entity.IsDeleted = true;
    entry.Entity.DeletedAt = DateTime.UtcNow;
}

// Normal query - filter applied automatically:
var activeProducts = await ctx.Products
    .Where(p => p.CategoryId == categoryId).ToListAsync();

// Admin restore - bypass the filter:
var deletedProducts = await ctx.Products
    .IgnoreQueryFilters()
    .Where(p => p.IsDeleted).ToListAsync();

// ❌ BAD - load-modify-save loop, one round-trip per row at scale
var products = await ctx.Products
    .Where(p => p.CategoryId == 5).ToListAsync();
foreach (var p in products)
    p.Price = p.Price * 1.1m;
await ctx.SaveChangesAsync(); // very slow on 50,000 rows

// ✅ GOOD - single UPDATE statement, no loading, no tracking
await ctx.Products
    .Where(p => p.CategoryId == 5)
    .ExecuteUpdateAsync(s => s
        .SetProperty(p => p.Price, p => p.Price * 1.1m)
        .SetProperty(p => p.UpdatedAt, _ => DateTime.UtcNow));

// ✅ GOOD - set-based delete for log cleanup
await ctx.AuditLogs
    .Where(l => l.CreatedAt < DateTime.UtcNow.AddDays(-90))
    .ExecuteDeleteAsync();

// ✅ GOOD - high-volume insert via BulkExtensions
var newOrders = BuildOrders(10_000);
await ctx.BulkInsertAsync(newOrders);

// ❌ BAD - using EnsureCreated in production; it cannot evolve the schema later
await ctx.Database.EnsureCreatedAsync();

// ✅ GOOD - Code First + Migrations (the standard path)
// 1. Define your entity:
public class ShipmentRoute
{
    public int Id { get; set; }
    public string OriginCity { get; set; } = string.Empty;
    public string DestinationCity { get; set; } = string.Empty;
    public decimal CostPerKm { get; set; }
}
// 2. CLI: dotnet ef migrations add AddShipmentRoute
// 3. CLI: dotnet ef database update

// Database First: scaffold from existing schema:
// dotnet ef dbcontext scaffold "Server=.;Database=LogisticsDb;..." \
//     Microsoft.EntityFrameworkCore.SqlServer -o Models

// ❌ BAD - trying to use a shadow property for a multi-field value object (not possible)
// builder.Property<Address>("ShippingAddress"); // shadow properties are single columns only

// ✅ GOOD - multi-field value object mapped as an owned entity
public class Order
{
    public int Id { get; set; }
    public Address ShippingAddress { get; set; } = null!;
}
public class Address // no Id, no DbSet - pure value object
{
    public string Street { get; set; } = string.Empty;
    public string City { get; set; } = string.Empty;
    public string PostCode { get; set; } = string.Empty;
}
// In IEntityTypeConfiguration<Order>:
builder.OwnsOne(o => o.ShippingAddress, addr =>
{
    addr.Property(a => a.Street).HasMaxLength(200).IsRequired();
    addr.Property(a => a.City).HasMaxLength(100).IsRequired();
    addr.Property(a => a.PostCode).HasMaxLength(20).IsRequired();
});
// Single hidden audit column as a shadow property:
builder.Property<DateTime>("LastModified");

// ❌ BAD - two separate SaveChanges with no shared transaction; partial failure leaves bad state
await ctx.SaveChangesAsync(); // Order saved
await ctx.SaveChangesAsync(); // Payment - fails here leaves orphan Order

// ✅ GOOD - explicit transaction wrapping both SaveChanges calls
await using var tx = await ctx.Database.BeginTransactionAsync();
try
{
    ctx.Orders.Add(order);
    await ctx.SaveChangesAsync();
    ctx.Payments.Add(new Payment { OrderId = order.Id, Amount = order.Total });
    await ctx.SaveChangesAsync();
    await tx.CommitAsync(); // both succeed - commit
}
catch
{
    await tx.RollbackAsync(); // either fails - roll both back
    throw;
}

// With EnableRetryOnFailure - wrap in execution strategy:
var strategy = ctx.Database.CreateExecutionStrategy();
await strategy.ExecuteAsync(async () =>
{
    await using var tx2 = await ctx.Database.BeginTransactionAsync();
    ctx.Orders.Add(order);
    await ctx.SaveChangesAsync();
    await tx2.CommitAsync();
});

// ❌ BAD - two collection Includes without split query causes Cartesian explosion
var shipments = await ctx.Shipments
    .Include(s => s.Items)          // 20 items per shipment
    .Include(s => s.StatusHistory)  // 15 records per shipment
    .ToListAsync(); // returns 300 rows for what is 35 entities!

// ✅ GOOD - split query avoids row explosion
var shipments = await ctx.Shipments
    .Include(s => s.Items)
    .Include(s => s.StatusHistory)
    .AsSplitQuery()
    .AsNoTracking()
    .ToListAsync(); // 3 separate SELECTs: Shipments, Items, StatusHistory

// ✅ GOOD - for consistency-critical reads, wrap in a transaction
await using var tx = await ctx.Database.BeginTransactionAsync();
var financialShipments = await ctx.Shipments
    .Include(s => s.Items)
    .Include(s => s.StatusHistory)
    .AsSplitQuery().AsNoTracking().ToListAsync();
await tx.CommitAsync();
